&lt;p data-start=&quot;738&quot; data-end=&quot;792&quot;&gt;Track &lt;strong data-start=&quot;744&quot; data-end=&quot;792&quot;&gt;sales, refunds, chargebacks, fees, and taxes&lt;/strong&gt;&lt;/p&gt;
&lt;/li&gt;
&lt;li data-start=&quot;793&quot; data-end=&quot;850&quot;&gt;
&lt;p data-start=&quot;795&quot; data-end=&quot;850&quot;&gt;Record and reconcile &lt;strong data-start=&quot;816&quot; data-end=&quot;850&quot;&gt;inventory-related transactions&lt;/strong&gt;&lt;/p&gt;
&lt;/li&gt;
&lt;li data-start=&quot;851&quot; data-end=&quot;922&quot;&gt;
&lt;p data-start=&quot;853&quot; data-end=&quot;922&quot;&gt;Prepare &lt;strong data-start=&quot;861&quot; data-end=&quot;890&quot;&gt;monthly financial reports&lt;/strong&gt; (P&amp;amp;L, balance sheet, cash flow)&lt;/p&gt;
&lt;/li&gt;
&lt;li data-start=&quot;923&quot; data-end=&quot;979&quot;&gt;
&lt;p data-start=&quot;925&quot; data-end=&quot;979&quot;&gt;Assist with &lt;strong data-start=&quot;937&quot; data-end=&quot;964&quot;&gt;sales tax/VAT reporting&lt;/strong&gt; and compliance&lt;/p&gt;
&lt;/li&gt;
&lt;li

